import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import matplotlib.patches as patches; import numpy as np; fig, ax = plt.subplots(figsize=(6, 4)); ax.set_xlim(0, 8); ax.set_ylim(-0.8, 4); ax.set_aspect("equal"); ax.axis("off"); ax.add_patch(patches.Rectangle((1, 0), 2, 2, color="#eaf2fb", zorder=1)); ax.plot([1, 1, 3, 3], [3, 0, 0, 3], color="#1a1a1a", lw=2, zorder=2); ax.text(2, -0.5, "A", ha="center", fontsize=14, fontweight="bold"); ax.add_patch(patches.Rectangle((5, 0), 2, 2, color="#eaf2fb", zorder=1)); ax.plot([5, 5, 7, 7], [3, 0, 0, 3], color="#1a1a1a", lw=2, zorder=2); ax.text(6, -0.5, "B", ha="center", fontsize=14, fontweight="bold"); x_vals = np.linspace(5.1, 6.9, 50); y_vals = 0.4 * np.exp(-((x_vals - 6.0)**2) / 0.1); ax.fill_between(x_vals, 0, y_vals, color="#d2b48c", zorder=3); np.random.seed(42); dots_x = np.random.uniform(5.1, 6.9, 100); dots_y = np.random.uniform(0, 0.5, 100); mask = dots_y < 0.4 * np.exp(-((dots_x - 6.0)**2) / 0.1); ax.scatter(dots_x[mask], dots_y[mask], s=1.5, color="#8b7355", zorder=4); plt.savefig("out.png", dpi=150)